@app.route('/enable-mfa', methods=['POST'])
def enable_mfa():
    email = request.form['email']
    if email in mfa_enabled and mfa_enabled[email]:
        return 'MFA already enabled for this email', 400
    secret = secrets.token_urlsafe(16)
    mfa_secret[email] = secret
    mfa_enabled[email] = True
    send_reset_email(email)
    return 'MFA reset link sent to your email'

@app.route('/reset-mfa/<token>', methods=['GET'])
def reset_mfa(token):
    try:
        email = s.loads(token, salt='reset-password', max_age=3600)  # Link expires in 1 hour
    except:
        return 'Invalid or expired reset link', 400

    if not mfa_enabled.get(email, False):
        return 'MFA already disabled for this email', 400

    mfa_enabled[email] = False
    mfa_secret.pop(email, None)
    return 'MFA disabled successfully'

